            S[i] = Integer.parseInt(str[i]);

        // Read the third line of input, which is the size of array T
        int q = Integer.parseInt(br.readLine());
        // Read the fourth line of input, which contains the elements of array T
        str = br.readLine().split(" ");
        int[] T = new int[q];
        // Parse the elements of the array T from the input string
        for (int i = 0; i < q; i++)
            T[i] = Integer.parseInt(str[i]);

        // Call the method to count matching elements and print the result
        System.out.println(method(S, T));
    }

    // Method to count how many elements in array t are present in array s
    static int method(int[] s, int[] t) {
        // If array s is smaller than array t, swap them to ensure s is always the larger array
        if (s.length < t.length) {
            int[] tmp = s;
            s = t;
            t = tmp;
        }

        int count = 0; // Initialize a counter for matching elements
        int q = s.length / 4; // Calculate a quarter of the length of array s

        // Iterate over each element in array t
        for (int i = 0; i < t.length; i++) {
            // Check if the current element of t is greater than the midpoint of s
            if (t[i] > s[q * 2]) {
                // Further check if it is greater than the third quarter of s
                if (t[i] > s[q * 3]) {
                    // Search in the last quarter of s
                    for (int j = s[q * 3]; j < s.length; j++)
                        if (t[i] == s[j]) { count++; break; }
                } else if (t[i] < s[q * 3]) {
                    // Search in the third quarter of s
                    for (int j = q * 2; j < q * 3; j++)
                        if (t[i] == s[j]) { count++; break; }
                } else if (s[q * 3] == t[i]) { count++; continue; }
            } else if (t[i] < s[q * 2]) {
                // Check if the current element of t is greater than the first quarter of s
                if (t[i] > s[q]) {
                    // Search in the second quarter of s
                    for (int j = s[q + 1]; j < q * 2; j++)
                        if (t[i] == s[j]) { count++; break; }
                } else if (t[i] < s[q]) {
                    // Search in the first quarter of s
                    for (int j = 0; j < q; j++)
                        if (t[i] == s[j]) { count++; break; }
                } else if (s[q] == t[i]) { count++; continue; }
            } else if (s[s.length / 2] == t[i]) { count++; continue; }
        }

        // Return the count of matching elements
        return count;
    }
