    String s = sc.next();

    // Split the input string into an array of single-character strings
    String[] sList = s.split("");

    // Initialize an integer array to store the numeric values of the characters
    int[] intList = new int[s.length()];
    // Convert each character in the string to an integer and store it in intList
    for(int i = 0; i < s.length(); i++){
      intList[i] = Integer.parseInt(sList[i]);
    }

    // Initialize counters for the number of changes needed to start with black or white
    int startBlack = 0;
    int startWhite = 0;

    // Check the first character to determine the starting pattern
    if(intList[0] == 0) {
      // If the first character is 0, start with black (0)
      int next = 0;
      // Iterate through the array to count the number of changes needed
      for (int i = 0; i < s.length(); i++) {
        if(intList[i] == next) {
          // If the current character matches the expected pattern, switch the expected pattern
          if(next == 0) {
            next = 1;
          } else if (next == 1) {
            next = 0;
          }
        } else {
          // If the current character does not match, increment the startBlack counter
          startBlack++;
          // Switch the expected pattern
          if(next == 0) {
            next = 1;
          } else if (next == 1) {
            next = 0;
          }
        }
      }
    } else if (intList[0] == 1) {
      // If the first character is 1, start with white (1)
      int next = 1;
      // Iterate through the array to count the number of changes needed
      for (int i = 0; i < s.length(); i++) {
