            next = 0;
          }
        } else {
          // If the current character does not match, increment the startBlack counter
          startBlack++;
          // Switch the expected pattern
          if(next == 0) {
            next = 1;
          } else if (next == 1) {
            next = 0;
          }
        }
      }
    }

    // Compare the number of changes needed for both starting patterns
    if(startBlack > startWhite) {
      // If starting with black requires more changes, print startBlack
