        long ans = 0;

        // Determine the maximum product based on the sign of the numbers
        if(a >= 0 && b >= 0 && c >= 0 && d >= 0)
            ans = b * d;
        else if(a < 0 && b >= 0 && c >= 0 && d >= 0)
            ans = b * d;
