        int count = 0;
        // Boolean flag to determine if the condition is met
        boolean poss = false;
        // Read the number of pairs to process
        int n = sc.nextInt();
        // Loop through each pair
        for(int i = 0; i < n; i++)
        {
            // Read two integers from input
            int u = sc.nextInt(), v = sc.nextInt();
            // Check if the pair is equal
            if(u == v)
            {
                // Increment the counter if equal
                count++;
            }
            else
            {
                // Reset the counter if not equal
                count = 0;
            }
            // If three consecutive pairs are equal, set the flag to true
            if(count >= 3) poss = true;
        }
        // Print "Yes" if the condition is met, otherwise "No"
        p.println(poss ? "Yes" : "No");
        // Close the PrintWriter
        p.close();
    }

