        {
            arr.add(i);
        }
        // Sort the ArrayList
        Collections.sort(arr);
        // Copy the sorted elements back to the array
        for(int i = 0 ; i < arr.size(); i++)
        {
            a[i] = arr.get(i);
        }
        // Return the sorted array
        return a;
    }

