    public static void main(String[] args) {
        // Initialize an array 'a' with six elements, all set to -1
        int[] a = {-1, -1, -1, -1, -1, -1};

        // Variable 'dis' will store the distance between two elements in the array
        int dis;

        // Boolean flag 'is' to determine if the condition is met
        boolean is = true;

        // Create a Scanner object to read input from the user
        Scanner sc = new Scanner(System.in);

        // Loop until the input array 'a' satisfies the given conditions
        while (a[0] < 0 || a[1] < 0 || a[2] < 0 || a[3] < 0 || a[4] < 0 || a[5] < 0
                || a[0] > 123 || a[1] > 123 || a[2] > 123 || a[3] > 123 || a[4] > 123 || a[5] > 123
                || a[0] > a[1] || a[1] > a[2] || a[2] > a[3] || a[3] > a[4]) {

            // Read six integers from the user and store them in the array 'a'
            for (int i = 0; i < 6; i++) {
                a[i] = sc.nextInt();
            }
        }

        // Check the distances between each pair of elements in the first five positions of the array
        for (int i = 0; i < 4; i++) {
            for (int j = i + 1; j < 5; j++) {
                // Calculate the distance between elements at positions j and i
                dis = a[j] - a[i];

                // If the distance is greater than the last element in the array, print ":("
                if (dis > a[5]) {
                    System.out.println(":(");

                    // Break out of both loops by setting i and j to values that will terminate the loops
                    i = 4;
                    j = 6;

                    // Set the flag 'is' to false indicating the condition was not met
                    is = false;
                }
            }
        }

        // If the flag 'is' remains true, print "Yay!" indicating the condition was met
        if (is) {
            System.out.println("Yay!");
        }
    }
}

