// Custom scanner class for fast input reading
class FastScanner {
    // Reader object for input
    Reader input;

    // Constructor for standard input
    FastScanner() {this(System.in);}
    // Constructor for input from a stream
    FastScanner(InputStream stream) {this.input = new BufferedReader(new InputStreamReader(stream));}

    // Method to read the next integer from input
    int nextInt() {return (int) nextLong();}

    // Method to read the next long integer from input
    long nextLong() {
        try {
            int sign = 1;
            int b = input.read();
            // Skip non-numeric characters
            while ((b < '0' || '9' < b) && b != '-' && b != '+') {
                b = input.read();
            }
            // Handle negative numbers
            if (b == '-') {
                sign = -1;
                b = input.read();
            } else if (b == '+') {
                b = input.read();
            }
            // Read the number
            long ret = b - '0';
            while (true) {
                b = input.read();
                if (b < '0' || '9' < b) return ret * sign;
                ret *= 10;
                ret += b - '0';
            }
        } catch (IOException e) {
            e.printStackTrace();
            return -1;
        }
    }

    // Method to read the next double from input
    double nextDouble() {
        try {
            double sign = 1;
            int b = input.read();
            // Skip non-numeric characters
            while ((b < '0' || '9' < b) && b != '-' && b != '+') {
                b = input.read();
            }
            // Handle negative numbers
            if (b == '-') {
                sign = -1;
                b = input.read();
            } else if (b == '+') {
                b = input.read();
            }
            // Read the integer part
            double ret = b - '0';
            while (true) {
                b = input.read();
                if (b < '0' || '9' < b) break;
                ret *= 10;
                ret += b - '0';
            }
            // If no decimal point, return the integer part
            if (b != '.') return sign * ret;
            // Read the fractional part
            double div = 1;
            b = input.read();
            while ('0' <= b && b <= '9') {
                ret *= 10;
                ret += b - '0';
                div *= 10;
                b = input.read();
            }
            // Return the complete double value
            return sign * ret / div;
        } catch (IOException e) {
            e.printStackTrace();
            return Double.NaN;
        }
    }

    // Method to read the next non-whitespace character from input
    char nextChar() {
        try {
            int b = input.read();
            // Skip whitespace characters
            while (Character.isWhitespace(b)) {
                b = input.read();
            }
            return (char) b;
        } catch (IOException e) {
            e.printStackTrace();
            return 0;
        }
    }

    // Method to read the next string from input
    String nextStr() {
        try {
            StringBuilder sb = new StringBuilder();
            int b = input.read();
            // Skip leading whitespace
            while (Character.isWhitespace(b)) {
                b = input.read();
            }
            // Read characters until whitespace or end of stream
            while (b != -1 && !Character.isWhitespace(b)) {
                sb.append((char) b);
                b = input.read();
            }
            return sb.toString();
        } catch (IOException e) {
            e.printStackTrace();
            return "";
        }
    }
}

