public class Main {
    public static void main(String[] args) {
        // Initialize input and output streams
        InputStream inputStream = System.in;
        OutputStream outputStream = System.out;

        // Create a Scanner object for reading input
        Scanner in = new Scanner(inputStream);

        // Create a PrintWriter object for writing output
        PrintWriter out = new PrintWriter(outputStream);

        // Create an instance of the solver class B
        B solver = new B();

        // Call the solve method of class B with test number 1
        solver.solve(1, in, out);

        // Close the PrintWriter to release resources
        out.close();
    }

    static class B {
        // Method to solve the problem for a given test case
        public void solve(int testNumber, Scanner in, PrintWriter out) {

            // Read an integer n from input
            int n = Integer.parseInt(in.next());

            // Initialize a counter for the answer
            int ans = 0;

            // Loop from n down to 1
            while (n > 0) {
                // Check if n is odd
                if (n % 2 != 0) {
                    // Check various conditions and increment ans accordingly
                    if (n % 3 == 0 && n % 5 == 0 && n % 7 == 0) ans++;
                    if (n % 3 == 0 && n % 5 == 0 && n % 11 == 0) ans++;
                    if (n % 3 == 0 && n % 5 == 0 && n % 13 == 0) ans++;
                    if (n % 27 == 0 && n % 5 == 0) ans++;
                    if (n % 27 == 0 && n % 7 == 0) ans++;
                }
                // Decrement n to check the next number
                n--;
            }

